use distributed_inference::pleromatic_frame::{PleromaticFrame, PleromaticMediaType};
use std::io::{self, BufRead, Write};
use std::time::SystemTime;

/// Dialogue Residue Collector: Transforms human dialogue into Pleromatic frames.
///
/// Usage: echo "Hello Swarm" | dialogue-residue-collector | aeon-monitor
fn main() -> io::Result<()> {
    let stdin = io::stdin();
    let mut seq = 0u64;

    for line in stdin.lock().lines() {
        let line = line?;
        if line.trim().is_empty() {
            continue;
        }

        let now = SystemTime::now()
            .duration_since(SystemTime::UNIX_EPOCH)
            .unwrap()
            .as_millis() as u64;

        let mut frame = PleromaticFrame::grounding(
            "dialogue-collector".to_string(),
            PleromaticMediaType::Semantic,
            line.into_bytes(),
        );
        frame.seq = seq;
        frame.timestamp_ms = now;

        let encoded = bincode::serialize(&frame).map_err(io::Error::other)?;
        io::stdout().write_all(&encoded)?;
        io::stdout().flush()?;

        seq += 1;
    }

    Ok(())
}
